#!/usr/bin/bash
set -euo pipefail
systemctl is-active --quiet podman.socket

#!/usr/bin/bash
# Required: mios-role.service must have succeeded
set -euo pipefail
systemctl is-active --quiet mios-role.service || {
    echo "mios-role.service is not active"
    exit 1
}
test -f /var/lib/mios/role.active

#!/usr/bin/bash
set -euo pipefail
tgt=$(systemctl get-default)
case "$tgt" in
    mios-*.target|graphical.target|multi-user.target) exit 0 ;;
    *) echo "unexpected default target: $tgt"; exit 1 ;;
esac
